changeSet.sql:
CREATE TABLE departments (
    id UUID PRIMARY KEY,
    tenant_id UUID NOT NULL,
    code VARCHAR(50) NOT NULL,
    name VARCHAR(200) NOT NULL,
    description TEXT,
    parent_department_id UUID,
    manager_id UUID,
    is_active BOOLEAN DEFAULT true NOT NULL,
    location VARCHAR(500),
    cost_center VARCHAR(20),
    type VARCHAR(50),
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP NOT NULL,
    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP NOT NULL,
    version BIGINT DEFAULT 0 NOT NULL
);

CREATE UNIQUE INDEX idx_department_code_tenant ON departments(code, tenant_id);
CREATE INDEX idx_department_tenant ON departments(tenant_id);
CREATE INDEX idx_department_parent ON departments(parent_department_id);

ALTER TABLE departments ADD CONSTRAINT fk_department_parent FOREIGN KEY (parent_department_id) REFERENCES departments(id) ON DELETE CASCADE;
